changeSet.sql:
UPDATE achievements SET metric = 'TOTAL_DISTANCE_KM'
  WHERE metric IS NULL AND category = 'DISTANCE';
UPDATE achievements SET metric = 'STREAK_DAYS'
  WHERE metric IS NULL AND category = 'STREAK';
UPDATE achievements SET metric = 'PR_DISTINCT_DISTANCES'
  WHERE metric IS NULL AND achievement_key = 'pr_all_distances';
UPDATE achievements SET metric = 'PR_TOTAL_COUNT'
  WHERE metric IS NULL AND category = 'PR';
UPDATE achievements SET metric = 'PERFECT_WEEKS_COUNT'
  WHERE metric IS NULL AND achievement_key LIKE 'week_100_pct%';
UPDATE achievements SET metric = 'COMPLETED_PLANS_COUNT'
  WHERE metric IS NULL AND category = 'PLAN_COMPLETION';
